import axios from 'axios';

const API = axios.create({
  baseURL: 'http://localhost:8080/api',
  headers: {
    'Content-Type': 'application/json',
  },
});

// ==============================
// REQUEST INTERCEPTOR
// ==============================
API.interceptors.request.use(
  (config) => {
    const token = localStorage.getItem('token');

    console.log("TOKEN:", token);

    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }

    return config;
  },
  (error) => Promise.reject(error)
);

// ==============================
// RESPONSE INTERCEPTOR
// ==============================
API.interceptors.response.use(
  (response) => response,
  (error) => {

    console.log("API ERROR:", error.response);

    if (error.response?.status === 401) {
      localStorage.removeItem('token');
      localStorage.removeItem('user');
      window.location.href = '/login';
    }

    return Promise.reject(error);
  }
);

// ==============================
// AUTH APIs
// ==============================
export const authAPI = {
  register: (data) => API.post('/auth/register', data),
  login: (data) => API.post('/auth/login', data),
};

// ==============================
// PRODUCT APIs
// ==============================
export const productAPI = {
  getAll: (params) => API.get('/products', { params }),
  getFeatured: () => API.get('/products/featured'),
  getNewArrivals: () => API.get('/products/new-arrivals'),
  getById: (id) => API.get(`/products/${id}`),
  getCategories: () => API.get('/products/categories'),
};

// ==============================
// CART APIs
// ==============================
export const cartAPI = {
  getCart: () => API.get('/cart'),

  addItem: (data) => API.post('/cart/add', data),

  updateItem: (itemId, quantity) =>
    API.put(`/cart/update/${itemId}`, { quantity }),

  removeItem: (itemId) =>
    API.delete(`/cart/remove/${itemId}`),

  clearCart: () =>
    API.delete('/cart/clear'),
};

// ==============================
// ORDER APIs
// ==============================
export const orderAPI = {

  checkout: (data) => {
    console.log("CHECKOUT REQUEST:", data);
    return API.post('/orders/checkout', data);
  },

  verifyPayment: (data) => {
    console.log("VERIFY PAYMENT:", data);
    return API.post('/orders/payment/verify', data);
  },

  getMyOrders: () => API.get('/orders/my'),

  getOrder: (id) => API.get(`/orders/${id}`),
};

// ==============================
// ADMIN APIs
// ==============================
export const adminAPI = {

  getDashboard: () =>
    API.get('/admin/dashboard'),

  getProducts: (params) =>
    API.get('/admin/products', { params }),

  createProduct: (data) =>
    API.post('/admin/products', data, {
      headers: { 'Content-Type': 'multipart/form-data' }
    }),

  updateProduct: (id, data) =>
    API.put(`/admin/products/${id}`, data, {
      headers: { 'Content-Type': 'multipart/form-data' }
    }),

  deleteProduct: (id) =>
    API.delete(`/admin/products/${id}`),

  getOrders: (params) =>
    API.get('/admin/orders', { params }),

  updateOrderStatus: (id, status) =>
    API.put(`/admin/orders/${id}/status`, { status }),

  getUsers: () =>
    API.get('/admin/users'),
};

export default API;
